/// Serves files from the `./uploads` directory.
///
/// Accepts the filename (potentially with subdirectories) from the URL path.
/// Example: `/uploads/my_file.txt` or `/uploads/documents/report.pdf`
async fn serve_upload(path: web::Path<String>) -> actix_web::Result<HttpResponse> {
    let filename_with_path = path.into_inner();
    let base_uploads_dir = PathBuf::from("./uploads"); // Base directory for uploads

    // Construct the full path to the requested file
    let requested_file_path = base_uploads_dir.join(&filename_with_path);

    // --- Security check: Prevent directory traversal ---
    // Canonicalize both the base directory and the requested file path.
    // This resolves any '..' components and symlinks.
    let canonical_base_dir = fs::canonicalize(&base_uploads_dir)
        .await
        .map_err(|e| {
            actix_web::error::ErrorInternalServerError(format!("Failed to canonicalize base uploads directory: {}", e))
        })?;

    // Attempt to canonicalize the requested file path.
    // If it doesn't exist, canonicalize will return NotFound, which we handle.
    let canonical_requested_file_path = fs::canonicalize(&requested_file_path)
        .await
        .map_err(|e| {
            if e.kind() == std::io::ErrorKind::NotFound {
                actix_web::error::ErrorNotFound(format!("File not found: {}", filename_with_path))
            } else {
                actix_web::error::ErrorInternalServerError(format!("Error accessing file: {}", e))
            }
        })?;

    // Ensure the canonicalized requested file path is indeed a descendant of the canonicalized base directory.
    if !canonical_requested_file_path.starts_with(&canonical_base_dir) {
        return Ok(HttpResponse::BadRequest().body("Invalid file path. Directory traversal attempt detected."));
    }
    // --- End security check ---

    // Read the file content into a byte vector
    let file_content = fs::read(&requested_file_path)
        .await
        .map_err(|e| {
            // This error handling might be redundant if canonicalize already caught NotFound,
            // but it's good to keep in case of other IO errors after the path check.
            if e.kind() == std::io::ErrorKind::NotFound {
                actix_web::error::ErrorNotFound(format!("File not found: {}", filename_with_path))
            } else {
                actix_web::error::ErrorInternalServerError(format!("Failed to read file: {}", e))
            }
        })?;

    // Guess the MIME type based on the file extension
    let mime_type = mime_guess::from_path(&requested_file_path).first_or_octet_stream();

    // Return the file content with the appropriate Content-Type header
    Ok(HttpResponse::Ok()
        .content_type(mime_type.as_ref())
        .body(file_content))
}

